import{isAddress,isHex,keccak256,leftPad,numberToHex,padLeft}from"web3-utils";import{guessKeyTypeFromKeyName}from"./utils";const dynamicTypes=["<string>","<address>","<bool>"],dynamicTypesRegex=/<(uint|int|bytes)(\d+)>/,encodeDynamicKeyPart=(e,n,r)=>{let t="",i=0;if(dynamicTypes.includes(e))t=e.slice(1,-1);else{var a=e.match(dynamicTypesRegex);if(!a)throw new Error(`Dynamic key: ${e} is not supported`);t=a[1],i=parseInt(a[2],10)}switch(t){case"string":return keccak256(n).slice(2,2+2*r);case"bool":if("true"!==n&&"false"!==n)throw new Error(`Wrong value: ${n} for dynamic key with type: <bool>. Expected "true" or "false".`);return leftPad(+("true"===n),2*r).slice(2);case"address":if(isAddress(n))return(20<r?leftPad(n.replace("0x",""),2*r):n.replace("0x","").slice(0,2*r)).toLowerCase();throw new Error(`Wrong value: ${n} for dynamic key with type: <address>. Value is not an address.`);case"uint":{if(256<i||i%8!=0)throw new Error(`Wrong dynamic key type: ${e}. 0 < M <= 256, M % 8 == 0. Got: ${i}.`);const c=numberToHex(n).slice(2);return c.length<=2*r?padLeft(c,2*r):c.slice(2*-r)}case"int":throw new Error("The encoding of <intM> has not been implemented yet.");case"bytes":{const o=n.replace("0x","");if(o.length!==2*i)throw new Error(`Wrong value: ${n} for dynamic key with type: ${e}. Value is not ${i} bytes long.`);if(isHex(o))return o.length>2*r?o.slice(0,2*r):leftPad(o,2*r).toLowerCase();throw new Error(`Wrong value: ${n} for dynamic key with type: ${e}. Value is not in hex.`)}default:throw new Error(`Dynamic key: ${e} is not supported`)}};function isDynamicKeyName(e){const n=e.split(":");for(let e=0;e<n.length;e++)if(dynamicTypes.includes(n[e])||n[e].match(dynamicTypesRegex))return!0;return!1}const encodeDynamicMapping=(e,n)=>{if(1!==n.length)throw new Error(`Dynamic key of type: Mapping expects exactly 1 variable. Got: ${n.length} (${n})`);e=e.split(":");return keccak256(e[0]).slice(0,22)+"0000"+encodeDynamicKeyPart(e[1],n[0],20)},encodeDynamicMappingWithGrouping=(e,n)